&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/alternate-methord-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Alternate Method&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;By checking options and substituting accordingly.&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;1) IQFQII &amp;nbsp;&amp;rarr;&lt;/strong&gt;&amp;nbsp;Q&amp;nbsp;&lt;strong&gt;I&amp;nbsp;Q&lt;/strong&gt;&amp;nbsp;T -&amp;nbsp;&lt;strong&gt;F&lt;/strong&gt;&amp;nbsp;I&amp;nbsp;F&amp;nbsp;T -&amp;nbsp;&lt;strong&gt;Q&amp;nbsp;I&lt;/strong&gt;&amp;nbsp;F&amp;nbsp;T - Q&amp;nbsp;&lt;strong&gt;I&lt;/strong&gt;&amp;nbsp;F&amp;nbsp;T - Q&amp;nbsp;I&amp;nbsp;F&amp;nbsp;T&amp;nbsp;&amp;rArr; sequence not followed&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;2) IFQQII&amp;nbsp;&lt;span style=&quot;&quot;&gt;&amp;rarr;&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;&lt;/span&gt; Q&amp;nbsp;&lt;strong&gt;I&amp;nbsp;F&lt;/strong&gt;&amp;nbsp;T&amp;nbsp;-&amp;nbsp;&lt;strong&gt;Q&lt;/strong&gt;&amp;nbsp;I&amp;nbsp;F T&amp;nbsp;-&amp;nbsp;&lt;strong&gt;Q&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;I&lt;/strong&gt;&amp;nbsp;F&amp;nbsp;T&amp;nbsp;- Q&lt;strong&gt;&amp;nbsp;I&amp;nbsp;&lt;/strong&gt;F&amp;nbsp;T&amp;nbsp;- Q&amp;nbsp;I&amp;nbsp;F&amp;nbsp;T&amp;nbsp;&lt;span style=&quot;&quot;&gt;&amp;rArr; sequence&amp;nbsp;followed&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;3) IFIIFF&amp;nbsp;&amp;nbsp;&lt;span style=&quot;&quot;&gt;&amp;rarr;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;Q&amp;nbsp;&lt;strong&gt;I&amp;nbsp;F&lt;/strong&gt;&amp;nbsp;T -&amp;nbsp;&lt;strong&gt;I&amp;nbsp;&lt;/strong&gt;I&amp;nbsp;F&amp;nbsp;T -&lt;strong&gt; I&amp;nbsp;F&amp;nbsp;&lt;/strong&gt;F&amp;nbsp;T - Q&amp;nbsp;F&amp;nbsp;&lt;strong&gt;F&lt;/strong&gt;&amp;nbsp;T - Q&amp;nbsp;I&amp;nbsp;F&amp;nbsp;T&amp;nbsp;&lt;span style=&quot;&quot;&gt;&amp;rArr; sequence not followed&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;4) IFQQFF&lt;span style=&quot;&quot;&gt;&amp;rarr;&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;&lt;/span&gt;Q&amp;nbsp;&lt;strong&gt;I&amp;nbsp;F&lt;/strong&gt;&amp;nbsp;T -&lt;strong&gt;&amp;nbsp;Q&lt;/strong&gt;&amp;nbsp;I&amp;nbsp;F&amp;nbsp;T - &lt;strong&gt;Q&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;F&lt;/strong&gt;&amp;nbsp;F&amp;nbsp;T-&amp;nbsp; Q&amp;nbsp;&lt;strong&gt;F&lt;/strong&gt;&amp;nbsp;F&amp;nbsp;T - Q&amp;nbsp;I&amp;nbsp;F&amp;nbsp;T&amp;nbsp;&lt;span style=&quot;&quot;&gt;&amp;rArr; sequence not followed&lt;/span&gt;&lt;/p&gt;

