&lt;p&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;Case 2:&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/23/02/F1_Madhuri_SSC_03.02.2023_D65.png&quot; style=&quot;width: 432px; height: 112px;&quot; /&gt;&lt;/p&gt;

&lt;p&gt;3)&amp;nbsp;&lt;span style=&quot;&quot;&gt;Only Sunita stands exactly between Babita and Dixita.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;(Here case 2 is eliminated because this condition is not applied here)&lt;/span&gt;&lt;/p&gt;

